import re,sys
lines=open('/app/text.gcode').read().splitlines()
x=y=z=0.0; obj=None
pts=[]
for ln in lines:
    s=ln.strip()
    if s.startswith('M486'):
        m=re.match(r'M486 S(-?\d+)',s)
        if m: obj=int(m.group(1))
        continue
    if s.startswith('G1') or s.startswith('G0'):
        nx,ny,nz,e=x,y,z,None
        for tok in s.split()[1:]:
            c=tok[0]
            if c=='X': nx=float(tok[1:])
            elif c=='Y': ny=float(tok[1:])
            elif c=='Z': nz=float(tok[1:])
            elif c=='E': e=float(tok[1:])
        if obj==0 and e and e>0 and (nx!=x or ny!=y):
            # sample along the segment
            steps=max(1,int((abs(nx-x)+abs(ny-y))/0.5))
            for i in range(steps+1):
                t=i/steps
                pts.append((x+(nx-x)*t, y+(ny-y)*t, z))
        x,y,z=nx,ny,nz
print("pts",len(pts))
import pickle
pickle.dump(pts,open('/app/pts.pkl','wb'))
EOF
